prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName (COUNT(DISTINCT CONCAT(STR(?start),"|",STR(?end),"|",STR(?pathLen))) AS ?executionPaths) (MIN(?pathLen) AS ?minLen) (MAX(?pathLen) AS ?maxLen) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "01e9c28ede6a4695b91dd90b3e0c5f1b" ;
         bbo:name ?modelName .
  ?model tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  # starting nodes
  ?start a bboExt:StartEvent ; tai:belongsTo ?choreo .
  ?end a bboExt:EndEvent ; tai:belongsTo ?choreo .

  # enumerate paths up to a bounded length to approximate distinct execution paths
  {
    SELECT DISTINCT ?start ?end (COUNT(?step) AS ?pathLen) WHERE {
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef){1,20} ?end .

      # derive a length proxy: count traversed edges in a reified way isn't available,
      # so we use the number of hop patterns matched by binding via property-path rewriting
      # by capturing intermediate nodes
      ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?mid .
    }
    GROUP BY ?start ?end
  }
}
GROUP BY ?model ?modelName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?whichId ?idVal WHERE {
  VALUES ?idVal { "01e9c28ede6a4695b91dd90b3e0c5f1b" }

  ?model a bboExt:Model ;
         bbo:name ?modelName .

  OPTIONAL {
    ?model tai:normalizedId ?idVal .
    BIND ("normalizedId" AS ?whichId)
  }
  OPTIONAL {
    ?model tai:originalId ?idVal .
    BIND ("originalId" AS ?whichId)
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?whichId (COUNT(DISTINCT ?choreo) AS ?choreoCount) (COUNT(DISTINCT ?start) AS ?startCount) (COUNT(DISTINCT ?end) AS ?endCount) WHERE {
  VALUES ?idVal { "01e9c28ede6a4695b91dd90b3e0c5f1b" }

  ?model a bboExt:Model ;
         bbo:name ?modelName .

  OPTIONAL {
    ?model tai:normalizedId ?idVal .
    BIND ("normalizedId" AS ?whichId)
  }
  OPTIONAL {
    ?model tai:originalId ?idVal .
    BIND ("originalId" AS ?whichId)
  }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  OPTIONAL { ?start a bboExt:StartEvent ; tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent ; tai:belongsTo ?choreo . }
}
GROUP BY ?model ?modelName ?whichId
ORDER BY DESC(?choreoCount) DESC(?startCount) DESC(?endCount)
LIMIT 25
